+// Package e2e contains end-to-end tests for NTM UBS routing.
+// ubs_assignment_route_test.go validates assignment-aware routing via Agent Mail.
+//
+// Bead: bd-3rxri - Route UBS findings to assigned agents
+package e2e
+
+import (
+	"context"
+	"fmt"
+	"strings"
