+func TestComparePanel_ScrollOffset(t *testing.T) {
+	t.Log("TEST: TestComparePanel_ScrollOffset - starting")
+
+	panel := NewComparePanel()
+	panel.SetSize(80, 40)
+	panel.Focus()
+
